  ('police-b20a8cf8-moex-00084', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '一般易燃性縱火劑多為高揮發性有機物，必須使用適當的容器加以包裝保存，俾供實驗室分析鑑 識，如果使用不當之容器可能導致縱火劑漏失或污染，下列何者不適合包裝縱火殘跡？', '["聚乙烯類塑膠袋", "聚酯類塑膠袋", "耐隆類塑膠袋", "乾淨鐵罐"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00085', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '於屍體上顯現指紋跡證，對於破案有莫大助益，請問下列何者係適合用於顯現屍體指紋的方法？', '["寧海德林法", "氰丙烯酸酯法", "碘-銀板轉印法", "磁粉法  ⑤矽膠法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00086', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '現場某些環境因子會對於DNA造成傷害，下列何者敘述正確？①微生物污染所釋出的核酸水解', '["強氧化劑提供能量促DNA形成鹼基鍵結而突變", "強酸破壞鍵結而使 DNA去嘌呤或斷裂", "強鹼和高溫會破壞氫鍵，使DNA雙股分開成單股", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00087', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '依內政部警政署於民國112年修正發布之刑事鑑識手冊中有關槍擊殘跡證物之處理原則，下列何 者敘述錯誤？', '["採取槍擊殘跡，應以黏有雙面碳膠之鋁（銅）座分別黏取不同部位，並分別標示其採證位置", "採取手部槍擊殘跡，宜於案發後8小時內儘速採集未經清洗、擦拭、救護之手部殘跡", "採取其他相關之槍擊殘跡，宜於案發後12小時內儘速採集未經清洗、血跡污染之最外層衣物 表面殘跡", "同案有槍彈證物可供鑑定者，以槍擊殘跡證物之鑑定為優先，並將槍彈證物暫時保存，視案情 需要，再行送鑑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00088', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '鑑識人員於暴力刑案現場中常會發現許多疑似血跡的生物性跡證，鑑識人員使用血跡初步檢測試 劑進行初篩，以釐清相關案情，請問下列何者非血跡初步檢測試劑？', '["鄰聯-甲苯胺（Ortho-tolidine）", "二苯胺（Diphenylamine）", "四甲基聯苯胺（Tetramethylbenzideine）", "無色孔雀綠（Leucomalachitegreen）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00089', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '鑑識人員分析實驗數據時，必須鑑別真實樣品訊號與雜訊（noise）之間差異，才能做出正確判斷， 若空白樣品訊號平均值為μ，標準差為σ，下列敘述何者錯誤？', '["偵測極限（limitofdetection）：樣品訊號必須大於μ+3σ", "確認極限（limitofidentification）：樣品訊號必須大於μ+6σ", "可靠偵測極限（reliabledetectionlimit）：樣品訊號必須大於μ+8σ", "定量極限（limitofquantitation）：樣品訊號必須大於μ+10σ"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00090', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有一塊磚頭不明原因從天而降，砸死一位路過老婦，鑑識人員於磚頭上發現有數十根可疑紫色纖 維，欲對紫色纖維上染料進行鑑定，下列檢驗方法敘述何者錯誤？', '["比對顯微鏡法（Comparison microscopy）：將纖維放置在載玻片上，並浸在 XMA mounting medium中，先以白光，後以紫外光為光源，觀察並記錄其差異性", "顯微光譜法（Microspectrophotometry）：將上述載玻片上之纖維以顯微光譜儀繪出波長 400～700nm的光譜，以為比對", "溶液光譜法（Solutionspectrometry）：測定纖維染料萃取液在波長280～580nm之紅外光範圍 的光譜", "薄層層析法（Thinlayerchromatography）：可用以進行纖維染料的分離比對"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00091', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '鑑識人員從一位疑似車禍肇事逃逸之駕駛身上採獲數枚可疑玻璃碎片，欲對這些很少量之玻璃碎 片進行非破壞性元素分析，請問下列何種鑑別方法最為適當？', '["原子吸收光譜法（AAS；Atomicabsorptionspectroscopy）", "導感耦合電漿原子發射光譜法（ICP-AES；Inductively coupled plasma atomic emission spectroscopy）", "氣相層析質譜法（GC-MS；Gaschromatographymassspectrometry）", "掃描電子顯微鏡/X光能譜法（SEM/EDX；Scanningelectronmicroscopy/energydispersiveX-ray spectrometry）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "c373d7869d8b", "answer_pdf_sha1": "bff41945785c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00092', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'essay', '為順利掌握國際犯罪組織走私販毒過程與流向，釐清販毒網絡與組織架
